import java.util.*;
import java.util.stream.*;

public class Main {
    abstract static class Shape { abstract int area(); }
    static final class Square extends Shape { private final int side; Square(int side) { this.side = side; } int area() { return side * side; } }
    static final class Rectangle extends Shape { private final int width, height; Rectangle(int width, int height) { this.width = width; this.height = height; } int area() { return width * height; } }

    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        String kind = input.next();
        Shape shape = kind.equals("square") ? new Square(input.nextInt()) : new Rectangle(input.nextInt(), input.nextInt());
        System.out.println(shape.area());
    }
}
